  ('locality-d592fc58-moex-00218', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '在梭羅模型 （SolowModel），人口成長率上升造成：', '["長短期資本－勞動比率都增加", "長短期資本－勞動比率都減少", "長期資本－勞動比率增加，短期資本－勞動比率減少", "長期資本－勞動比率減少，短期資本－勞動比率增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00219', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '短期下，當市場價格低於完全競爭廠商的平均總成本，廠商卻繼續營運的原因為何？', '["邊際收入大於邊際成本", "價格大於平均變動成本的最小值", "總固定成本小於總收入", "邊際成本最小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00220', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '假設甲國經濟一直處於充分就業的產出水準。以 AD-AS 模型分析，當甲國中央銀行在公開市場 上出售債券，且其他因素不變之下，短期內將導致：', '["實質GDP上升，而物價水準下跌", "實質GDP下降，而物價水準下跌", "實質GDP不變，而物價水準下跌", "實質GDP不變，而物價水準上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00221', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '民國109年的所得稅法規定，單身者標準扣除額為12萬元，每人的免稅額為8萬8千元，而薪 資扣除額為20萬元。個人的淨所得在54萬元以下，課稅5%，在54萬元到121萬元之間課12%， 在121萬元到242萬元之間課20%。如果小張和小李當年度的薪資所得分別為100萬元和140萬 元，分別算出他們適用平均稅率為何？', '["小張為3.3%，小李為3.8%", "小張為3.3%，小李為5.8%", "小張為5.3%，小李為3.8%", "小張為5.3%，小李為5.8%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00222', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '關於實質景氣循環理論的敘述，下列何者正確？', '["對抗景氣循環應從需求面著手", "假設工資與物價具有向下僵固性", "主張造成景氣循環的主因是實質面的影響，而非貨幣面的衝擊", "認為人們因為資訊不充分，常做了錯誤的判斷，而造成景氣循環"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00223', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '若中央銀行調高支付商業銀行準備金的利率，下列敘述何者正確？', '["因貨幣基數增加，貨幣供給增加", "因貨幣基數減少，貨幣供給減少", "因貨幣乘數變小，貨幣供給減少", "因貨幣乘數變大，貨幣供給增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00224', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '有關在準備金市場中，商業銀行同業間放款利率的敘述，下列何者最正確？', '["不會高於中央銀行支付商業銀行準備金利率", "不會低於貼現率", "可高於貼現率", "一般介於貼現率和中央銀行支付商業銀行準備金利率間變動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00225', 'locality-d592fc58', 'locality-d592fc58-moex-111-3082b5f1', 'sub-locality-d592fc58-06', NULL, 'essay', '甲與行政機關乙締結行政契約。其後行政機關乙認為締約後有情事重大
變更，乃向甲發公函逕行終止該契約。請問行政機關乙逕行終止該契約
之行為性質為何？若甲認為行政機關乙逕行終止該契約並不合法時，甲
得如何尋求救濟？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00226', 'locality-d592fc58', 'locality-d592fc58-moex-111-3082b5f1', 'sub-locality-d592fc58-06', NULL, 'essay', '甲生前為人作保，擔任其好友乙向丙借款 5 千萬之保證人，清償期為 110
年 12 月 15日。甲在 110 年 2 月9 日死亡，其子丁繼承其遺產。丁向國
稅局申報遺產稅時，主張其遺產總額應扣除甲生前所負之該筆保證債
務。但國稅局則以該筆主債務尚未屆清償期，故丁於繼承時尚未確定代
負履行之責，乃將該筆保證債務剔除。國稅局核定丁遺產稅之處分於110
年 8 月 8 日送達，丁於收受該處分書後隨即繳納遺產稅。其後乙於上開
債務清償期屆至後並未清償，且逃往外國不知去向。丙就乙之財產強制
執行無效果，乃請求丁代負履行責任。丁於代負清償該筆 5千萬之債務
後，深感自己繳了太多遺產稅。請問丁得否請求國稅局依據行政程序法
重開程序之規定，重新核定其遺產稅額？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00227', 'locality-d592fc58', 'locality-d592fc58-moex-111-3082b5f1', 'sub-locality-d592fc58-06', NULL, 'single_choice', '依實務見解，關於緊急命令，下列敘述何者正確？', '["總統僅於應付重大財政危機時，得經行政院會議之議決，發布緊急命令", "總統發布緊急命令之前，應徵詢立法院院長之意見", "緊急命令之內容應力求周延，以不得再授權為補充規定即可逕予執行為原則", "緊急命令得永久變更或取代相關法律之效力 31330"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL)
